<body>
    <label for="original-point-input">Original time (HH:MM):</label><br />
    <input id="original-point-input" type="text" /><br />

    <label for="time-left-input">Time left (HH:MM):</label><br />
    <input id="time-left-input" type="text" /><br />

    <label for="section-duration-input">Section duration (HH:MM):</label><br />
    <input id="section-duration-input" type="text" /><br />

    <button type="button" onclick="calculateOriginalPoint()">Calculate</button><br />

    <div id="output">Output will be displayed here.</div>

    <script>
        function calculateOriginalPoint() {
            var originalTime = document.getElementById('original-point-input').value;
            var timeLeft = document.getElementById('time-left-input').value;
            var sectionDuration = document.getElementById('section-duration-input').value;
            var output = document.getElementById('output');

            // Validate and parse the input times
            var timesAreValid = validateAndParseTimes(originalTime, timeLeft, sectionDuration);
            if (!timesAreValid) {
                output.textContent = 'Please enter valid times in HH:MM format.';
                return;
            }

            // Calculate the original point based on the valid times
            var startTimeFormatted = calculateTime(timesAreValid.originalHours, timesAreValid.originalMinutes, -timesAreValid.leftHours, -timesAreValid.leftMinutes);
            var endTimeFormatted = calculateTime(timesAreValid.originalHours, timesAreValid.originalMinutes, timesAreValid.sectionHours, timesAreValid.sectionMinutes);

            // Display the formatted time range
            output.textContent = `${startTimeFormatted} - ${endTimeFormatted}`;
        }

        function validateAndParseTimes(originalTime, timeLeft, sectionDuration) {
            // Regular expression to validate time format
            var timePattern = /^([01]?[0-9]|2[0-3]):([0-5][0-9])$/;

            // Validate and parse times
            if (timePattern.test(originalTime) && timePattern.test(timeLeft) && timePattern.test(sectionDuration)) {
                var [originalHours, originalMinutes] = originalTime.split(':').map(Number);
                var [leftHours, leftMinutes] = timeLeft.split(':').map(Number);
                var [sectionHours, sectionMinutes] = sectionDuration.split(':').map(Number);
                return {
                    originalHours,
                    originalMinutes,
                    leftHours,
                    leftMinutes,
                    sectionHours,
                    sectionMinutes
                };
            } else {
                return false;
            }
        }

        function calculateTime(startHours, startMinutes, deltaHours, deltaMinutes) {
            // Calculate the new time
            var hours = startHours + deltaHours;
            var minutes = startMinutes + deltaMinutes;

            // Normalize minutes
            while (minutes < 0) {
                minutes += 60;
                hours--;
            }
            while (minutes >= 60) {
                minutes -= 60;
                hours++;
            }

            // Normalize hours
            hours = (hours + 24) % 24;

            // Format time as HH:MM
            return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}`;
        }
